#include<bits/stdc++.h>
using namespace std;
int dp[11][91][91][91],a[11];
int dfs(int x,int sum,int num,int mod,bool lim)
{
    if(x==0)
    {
        return sum==mod&&(num==0);
    }
    if(!lim&&(dp[x][sum][num][mod]!=-1))
    {
        return dp[x][sum][num][mod];
    }
    int ans=0;
    int up=(lim?a[x]:9);
    for(int i=0;i<=up;i++)
    {
        if(sum+i<=mod)
        {
            ans+=dfs(x-1,sum+i,(num*10+i)%mod,mod,lim&&(i==a[x]));
        }
    }
    if(!lim)
    {
        dp[x][sum][num][mod]=ans;
    }
    return ans;
}
int calc(int x)
{
    int len=0;
    for(int i=x;i>0;i/=10)
    {
        a[++len]=i%10;
    }
    int ans=0;
    for(int i=len*9;i>=1;i--)
    {
        ans+=dfs(len,0,0,i,1);
    }
    return ans;
}
int main()
{
    memset(dp,-1,sizeof(dp));
    int l,r;
    while(scanf("%d%d",&l,&r)==2)
    {
        printf("%d\n",calc(r)-calc(l-1));
    }
    return 0;
}
